def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    weight = ((ratio - a) ** 7) / (a * b * 1.1 + 2)
                    priority += weight * np.tan(ratio * b / (a + 2))
            priority += (np.cosh(ratio - 7) * np.sin(ratio * 1.3)) ** 2.2
            if ratio > 10:
                for z in range(1, 5):
                    priority -= np.exp(-z * ratio) * np.cos(ratio * z)
        elif 5 < ratio <= 8:
            s1 = 0
            for m in range(1, int(np.ceil(ratio)) + 5):
                for n in range(1, m + 4):
                    term = ((ratio - m) ** 4) * np.cos(ratio * m * 1.2) / (n + 1.5)
                    s1 += np.tanh(term) * 1.8
            priority = s1 + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            for idx2 in range(1, 6):
                priority += np.sin(ratio * idx2 * i) * 0.5
        elif 2 <= ratio <= 5:
            s2 = 0
            for r in range(1, 15):
                coef = ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.1)
                s2 += coef
            priority = (s2 * np.sin(5 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2
            if i % 2 == 0:
                priority += np.sin(i * ratio) * 1.2
            else:
                priority -= np.cos(i * ratio) * 1.2
        elif 1.0 <= ratio < 2:
            s3 = 0
            for n in range(1, 12):
                s3 += ((2 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s3 + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1.0) ** m) / m
        elif 0.4 <= ratio < 1.0:
            s4 = 0
            for n in range(1, 20):
                s4 += ((1.0 - ratio) ** n) / (n * 3.5)
            if (i * int(item * 2)) % 5 == 0:
                priority = s4 * np.log1p(bin_cap + 4) * 1.5
            else:
                priority = s4 / (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1.0 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s5 = 0
            for k in range(1, 18):
                s5 += ((0.4 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.3)
            priority = s5 + 2 / (bin_cap + 4)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s6 = 0
            for t in range(1, 15):
                s6 += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.2)
            priority = s6 + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 1.1)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx3 in range(1, 6):
            if (i + idx3 * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx3) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx3) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        priorities[i] = priority
    return priorities
